pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/// @notice Mock PancakeSwap Router for testing — simulates swaps at 1:1 ratio
contract MockPancakeRouter {
    using SafeERC20 for IERC20;

    function factory() external pure returns (address) {
        return address(0);
    }

    function WETH() external pure returns (address) {
        return address(0);
    }

    /// @dev Mock swap: transfers tokenIn from sender, mints equivalent tokenOut to recipient
    function swapExactTokensForTokensSupportingFeeOnTransferTokens(
        uint256 amountIn,
        uint256 /* amountOutMin */,
        address[] calldata path,
        address to,
        uint256 /* deadline */
    ) external {
        IERC20(path[0]).safeTransferFrom(msg.sender, address(this), amountIn);
        // In tests, the mock just transfers from its own balance (pre-funded)
        IERC20(path[1]).safeTransfer(to, amountIn); // 1:1 swap rate for testing
    }

    function addLiquidity(
        address tokenA,
        address tokenB,
        uint256 amountADesired,
        uint256 amountBDesired,
        uint256 /* amountAMin */,
        uint256 /* amountBMin */,
        address to,
        uint256 /* deadline */
    ) external returns (uint256 amountA, uint256 amountB, uint256 liquidity) {
        IERC20(tokenA).safeTransferFrom(msg.sender, address(this), amountADesired);
        IERC20(tokenB).safeTransferFrom(msg.sender, address(this), amountBDesired);
        return (amountADesired, amountBDesired, amountADesired); // Mock LP tokens
    }
}

contracts/OSLODAO.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./libraries/OSLOConstants.sol";
import "./interfaces/IDAO.sol";
import "./interfaces/IInvestmentEngine.sol";

/// @title OSLODAO
/// @notice DAO entry qualification, monthly royalty distribution, and protocol governance.
/// @dev V2: USDT-based. First 200 users with 250+ team members qualify permanently for monthly royalties. Royalties paid in USDT.
contract OSLODAO is IDAO, ReentrancyGuard {
    using SafeERC20 for IERC20;

    // ─── State ──────────────────────────────────────────────────────────

    IERC20 public immutable usdt;
    address public investmentEngine;   // For combined 3X cap tracking

    address[] public daoMembers;
    mapping(address => bool) public override isDAOMember;

    /// @notice Monthly turnover tracking: monthId => totalTurnover
    mapping(uint256 => uint256) public monthlyTurnover;

    /// @notice Whether a member has claimed royalty for a given month
    mapping(address => mapping(uint256 => bool)) public royaltyClaimed;

    /// @notice Royalty pool balance (USDT)
    uint256 public royaltyPoolBalance;

    /// @notice Total royalties distributed all-time (USDT)
    uint256 public totalRoyaltiesDistributed;

    /// @notice Genesis timestamp for month calculation
    uint256 public immutable genesisTimestamp;

    address public admin;
    address public timelock;
    bool public setupComplete;

    // ─── Events ─────────────────────────────────────────────────────────
    event DAOMemberQualified(address indexed user, uint256 memberNumber, uint256 teamSize);
    event RoyaltyClaimed(address indexed user, uint256 amount, uint256 monthId);
    event RoyaltyPoolFunded(uint256 amount);
    event MonthlyTurnoverRecorded(uint256 monthId, uint256 amount);

    // ─── Errors ─────────────────────────────────────────────────────────
    error OnlyAdmin();
    error OnlyTimelock();
    error SetupAlreadyComplete();
    error MaxDAOMembersReached();
    error AlreadyDAOMember();
    error NotDAOMember();
    error AlreadyClaimed();
    error NoRoyalty();
    error InsufficientRoyaltyPool();
    error CurrentMonthNotClaimable();
    error ZeroAddress();

    modifier onlyAdmin() {
        if (msg.sender != admin) revert OnlyAdmin();
        _;
    }

    constructor(address _usdt) {
        if (_usdt == address(0)) revert ZeroAddress();
        usdt = IERC20(_usdt);
        admin = msg.sender;
        genesisTimestamp = block.timestamp;
    }

    // ─── Setup ──────────────────────────────────────────────────────────

    function configure(address _timelock, address _investmentEngine) external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        timelock = _timelock;
        investmentEngine = _investmentEngine;
    }

    function completeSetup() external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        setupComplete = true;
        admin = address(0);
    }

    // ─── Core Functions ─────────────────────────────────────────────────

    /// @notice Check if a user qualifies for DAO membership (called by Referral or Engine)
    /// @param user Address to check
    /// @param teamSize Total team size across 20 levels
    function checkAndQualify(address user, uint256 teamSize) external override {
        if (isDAOMember[user]) return;
        if (daoMembers.length >= OSLOConstants.MAX_DAO_MEMBERS) return;
        if (teamSize < OSLOConstants.DAO_TEAM_SIZE_REQUIREMENT) return;

        isDAOMember[user] = true;
        daoMembers.push(user);

        emit DAOMemberQualified(user, daoMembers.length, teamSize);
    }

    /// @notice Receive USDT into the royalty pool from Treasury
    function receiveRoyaltyPool(uint256 amount) external override {
        usdt.safeTransferFrom(msg.sender, address(this), amount);
        royaltyPoolBalance += amount;
        emit RoyaltyPoolFunded(amount);
    }

    /// @notice Record monthly protocol turnover for royalty calculation
    function recordMonthlyTurnover(uint256 amount) external override {
        uint256 monthId = getCurrentMonthId();
        monthlyTurnover[monthId] += amount;
        emit MonthlyTurnoverRecorded(monthId, amount);
    }

    /// @notice Claim monthly royalty (0.5% of previous month's turnover, split among DAO members)
    /// @dev Paid in USDT directly. Notifies InvestmentEngine for combined 3X cap tracking.
    function claimRoyalty() external override nonReentrant {
        if (!isDAOMember[msg.sender]) revert NotDAOMember();

        uint256 currentMonth = getCurrentMonthId();
        if (currentMonth <= 1) revert NoRoyalty();

        uint256 claimMonth = currentMonth - 1;
        if (royaltyClaimed[msg.sender][claimMonth]) revert AlreadyClaimed();

        uint256 turnover = monthlyTurnover[claimMonth];
        if (turnover == 0) revert NoRoyalty();

        // Total royalty pool for the month = 0.5% of turnover
        uint256 totalRoyalty = (turnover * OSLOConstants.DAO_MONTHLY_ROYALTY_BP) / OSLOConstants.BASIS_POINTS;
        // Each member gets equal share
        uint256 memberCount = daoMembers.length;
        if (memberCount == 0) revert NoRoyalty();

        uint256 memberShare = totalRoyalty / memberCount;
        if (memberShare == 0) revert NoRoyalty();
        if (memberShare > royaltyPoolBalance) revert InsufficientRoyaltyPool();

        royaltyClaimed[msg.sender][claimMonth] = true;
        royaltyPoolBalance -= memberShare;
        totalRoyaltiesDistributed += memberShare;

        // Notify InvestmentEngine for combined 3X cap tracking
        if (investmentEngine != address(0)) {
            IInvestmentEngine(investmentEngine).notifyLevelIncome(msg.sender, memberShare);
        }

        // Pay royalty in USDT directly
        usdt.safeTransfer(msg.sender, memberShare);

        emit RoyaltyClaimed(msg.sender, memberShare, claimMonth);
    }

    // ─── View Functions ─────────────────────────────────────────────────

    function daoMemberCount() external view override returns (uint256) {
        return daoMembers.length;
    }

    function getCurrentMonthId() public view returns (uint256) {
        return (block.timestamp - genesisTimestamp) / 30 days + 1;
    }

    function getPendingRoyalty(address user) external view returns (uint256) {
        if (!isDAOMember[user]) return 0;
        uint256 currentMonth = getCurrentMonthId();
        if (currentMonth <= 1) return 0;

        uint256 claimMonth = currentMonth - 1;
        if (royaltyClaimed[user][claimMonth]) return 0;

        uint256 turnover = monthlyTurnover[claimMonth];
        if (turnover == 0) return 0;

        uint256 totalRoyalty = (turnover * OSLOConstants.DAO_MONTHLY_ROYALTY_BP) / OSLOConstants.BASIS_POINTS;
        uint256 memberCount = daoMembers.length;
        if (memberCount == 0) return 0;

        return totalRoyalty / memberCount;
    }

    function getAllDAOMembers() external view returns (address[] memory) {
        return daoMembers;
    }
}

contracts/OSLODEX.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./libraries/OSLOConstants.sol";
import "./interfaces/IOSLODEX.sol";

/// @title OSLODEX
/// @notice Custom DEX for OSLO/USDT trading. Protocol-controlled liquidity.
/// @dev V2: USDT-based. Price = USDT reserve / OSLO total supply.
contract OSLODEX is IOSLODEX, ReentrancyGuard {
    using SafeERC20 for IERC20;

    // ─── State ────────────────────────────────────────────────────────

    IERC20 public immutable usdt;
    IERC20 public immutable osloToken;

    address public admin;
    address public timelock;
    address public liquidityManager;
    address public investmentEngine;   // Authorized to call processDeposit/processWithdrawal
    bool public setupComplete;

    // Reserves
    uint256 public usdtReserve;
    uint256 public osloReserve;

    // Stats
    uint256 public totalVolumeUSDT;
    uint256 public totalSwaps;
    uint256 public lastPrice; // Last trade price (USDT per OSLO, 18 decimals)

    // ─── Events ─────────────────────────────────────────────────────────
    event LiquidityDeposited(uint256 usdtAmount, uint256 osloAmount);
    event Swapped(
        address indexed user,
        bool usdtToOslo,
        uint256 inputAmount,
        uint256 outputAmount,
        uint256 price
    );
    event PriceUpdated(uint256 newPrice);
    event DepositProcessed(uint256 usdtIn, uint256 osloOut);
    event WithdrawalProcessed(uint256 osloIn, uint256 usdtOut, address recipient);

    // ─── Errors ─────────────────────────────────────────────────────────
    error OnlyAdmin();
    error OnlyTimelock();
    error OnlyLiquidityManager();
    error OnlyInvestmentEngine();
    error SetupAlreadyComplete();
    error ZeroAmount();
    error ZeroAddress();
    error InsufficientReserve();
    error SlippageExceeded();

    modifier onlyAdmin() {
        if (msg.sender != admin) revert OnlyAdmin();
        _;
    }

    modifier onlyTimelock() {
        if (msg.sender != timelock) revert OnlyTimelock();
        _;
    }

    modifier onlyLiquidityManager() {
        if (msg.sender != liquidityManager) revert OnlyLiquidityManager();
        _;
    }

    modifier onlyInvestmentEngine() {
        if (msg.sender != investmentEngine) revert OnlyInvestmentEngine();
        _;
    }

    constructor(address _usdt, address _osloToken) {
        if (_usdt == address(0) || _osloToken == address(0)) revert ZeroAddress();
        usdt = IERC20(_usdt);
        osloToken = IERC20(_osloToken);
        admin = msg.sender;
    }

    // ─── Setup ──────────────────────────────────────────────────────────

    function configure(address _timelock, address _liquidityManager, address _investmentEngine) external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        timelock = _timelock;
        liquidityManager = _liquidityManager;
        investmentEngine = _investmentEngine;
        setupComplete = true;
    }

    function completeSetup() external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        setupComplete = true;
        admin = address(0);
    }

    /// @notice Update the InvestmentEngine address. Only callable by Timelock.
    /// @param _investmentEngine New InvestmentEngine address
    function setInvestmentEngine(address _investmentEngine) external onlyTimelock {
        if (_investmentEngine == address(0)) revert ZeroAddress();
        investmentEngine = _investmentEngine;
    }

    /// @notice Force-update InvestmentEngine address. Only callable by Admin (pre-setup).
    /// @dev Used when redeploying IE before completeSetup is called.
    function forceSetInvestmentEngine(address _investmentEngine) external onlyAdmin {
        if (_investmentEngine == address(0)) revert ZeroAddress();
        investmentEngine = _investmentEngine;
    }

    // ─── Liquidity Management (Protocol-Controlled Only) ────────────────

    /// @notice Add initial liquidity to the DEX (called once during deployment)
    /// @param usdtAmount USDT amount
    /// @param osloAmount OSLO amount
    function addInitialLiquidity(uint256 usdtAmount, uint256 osloAmount) external onlyLiquidityManager {
        if (usdtAmount == 0 || osloAmount == 0) revert ZeroAmount();

        usdt.safeTransferFrom(msg.sender, address(this), usdtAmount);
        osloToken.safeTransferFrom(msg.sender, address(this), osloAmount);

        usdtReserve += usdtAmount;
        osloReserve += osloAmount;

        // Calculate initial price
        lastPrice = (usdtAmount * 1e18) / osloAmount;

        emit LiquidityDeposited(usdtAmount, osloAmount);
        emit PriceUpdated(lastPrice);
    }

    /// @notice Add more USDT liquidity from protocol fees.
    /// @param usdtAmount USDT amount to add
    function addLiquidityFromFees(uint256 usdtAmount) external onlyLiquidityManager {
        if (usdtAmount == 0) revert ZeroAmount();

        // Transfer USDT from LiquidityManager
        usdt.safeTransferFrom(msg.sender, address(this), usdtAmount);
        usdtReserve += usdtAmount;

        uint256 newPrice = (usdtReserve * 1e18) / osloToken.totalSupply();
        emit LiquidityDeposited(usdtAmount, 0);
        emit PriceUpdated(newPrice);
    }

    // ─── Investment Engine Protocol Functions ───────────────────────────

    /// @notice Process a deposit from InvestmentEngine: receive USDT, send OSLO to IE.
    /// @dev USDT must already be transferred to this contract (caller approves + transfers).
    ///      OSLO is sent to the caller (InvestmentEngine) from DEX reserves.
    /// @param usdtAmount Amount of USDT being deposited
    /// @return osloAmount Amount of OSLO sent to InvestmentEngine
    function processDeposit(uint256 usdtAmount) external override onlyInvestmentEngine nonReentrant returns (uint256 osloAmount) {
        if (usdtAmount == 0) revert ZeroAmount();

        // USDT should already be transferred by caller; pull from caller via transferFrom
        usdt.safeTransferFrom(msg.sender, address(this), usdtAmount);

        // Calculate OSLO to send back based on current DEX reserves
        // Constant-product-like: osloAmount = usdtAmount * osloReserve / (usdtReserve + usdtAmount)
        if (usdtReserve > 0 && osloReserve > 0) {
            osloAmount = (usdtAmount * osloReserve) / (usdtReserve + usdtAmount);
        } else {
            // Fallback: use initial price ratio if reserve is empty
            osloAmount = usdtAmount; // 1:1 if no price yet
        }

        if (osloAmount == 0) revert ZeroAmount();
        if (osloToken.balanceOf(address(this)) < osloAmount) revert InsufficientReserve();

        // Update reserves
        usdtReserve += usdtAmount;
        osloReserve -= osloAmount;

        // Send OSLO to InvestmentEngine
        osloToken.safeTransfer(msg.sender, osloAmount);

        // Update price: USDT per OSLO (18 decimals)
        uint256 newPrice = osloReserve > 0 ? (usdtReserve * 1e18) / osloReserve : 0;
        totalVolumeUSDT += usdtAmount;
        totalSwaps++;

        emit DepositProcessed(usdtAmount, osloAmount);
        emit PriceUpdated(newPrice);
    }

    /// @notice Process a withdrawal from InvestmentEngine: receive OSLO from IE, send USDT to recipient.
    /// @dev OSLO must already be transferred to this contract.
    /// @param osloAmount Amount of OSLO being returned
    /// @param recipient Address to receive USDT
    /// @return usdtAmount Amount of USDT sent to recipient
    function processWithdrawal(uint256 osloAmount, address recipient)
        external override onlyInvestmentEngine nonReentrant returns (uint256 usdtAmount)
    {
        if (osloAmount == 0) revert ZeroAmount();
        if (recipient == address(0)) revert ZeroAddress();

        // Pull OSLO from InvestmentEngine
        osloToken.safeTransferFrom(msg.sender, address(this), osloAmount);

        // Calculate USDT to return based on current DEX reserves
        if (usdtReserve > 0 && osloReserve > 0) {
            usdtAmount = (osloAmount * usdtReserve) / (osloReserve + osloAmount);
        } else {
            usdtAmount = osloAmount; // 1:1 fallback
        }

        if (usdtAmount == 0) revert ZeroAmount();
        if (usdtAmount > usdtReserve) revert InsufficientReserve();

        // Update reserves
        osloReserve += osloAmount;
        usdtReserve -= usdtAmount;

        // Send USDT to recipient
        usdt.safeTransfer(recipient, usdtAmount);

        uint256 newPrice = osloReserve > 0 ? (usdtReserve * 1e18) / osloReserve : 0;
        totalVolumeUSDT += usdtAmount;
        totalSwaps++;

        emit WithdrawalProcessed(osloAmount, usdtAmount, recipient);
        emit PriceUpdated(newPrice);
    }

    // ─── Yield Auto-Buy (Tax-Free) ────────────────────────────────────

    /// @notice Tax-free swap of USDT for OSLO — only callable by InvestmentEngine.
    /// @dev Used when claiming yield: yield USDT auto-buys OSLO at DEX rate with zero fee.
    ///      OSLO is sent directly to the recipient (the investor).
    /// @param usdtAmount Amount of USDT to swap (from IE's accumulated fees)
    /// @param recipient Address to receive OSLO tokens
    /// @return osloAmount Amount of OSLO sent to recipient
    function swapYieldForOSLO(uint256 usdtAmount, address recipient)
        external onlyInvestmentEngine nonReentrant returns (uint256 osloAmount)
    {
        if (usdtAmount == 0) revert ZeroAmount();
        if (recipient == address(0)) revert ZeroAddress();
        if (usdtReserve == 0 || osloReserve == 0) revert InsufficientReserve();

        // Constant product pricing — NO fee applied (tax-free yield buy)
        osloAmount = (usdtAmount * osloReserve) / (usdtReserve + usdtAmount);
        if (osloAmount == 0) revert ZeroAmount();

        // Pull USDT from InvestmentEngine
        usdt.safeTransferFrom(msg.sender, address(this), usdtAmount);

        // Send OSLO directly to the investor
        osloToken.safeTransfer(recipient, osloAmount);

        // Update reserves: USDT enters DEX (↑ liquidity), OSLO leaves DEX
        usdtReserve += usdtAmount;
        osloReserve -= osloAmount;

        // Update stats
        totalVolumeUSDT += usdtAmount;
        totalSwaps++;

        uint256 newPrice = osloReserve > 0 ? (usdtReserve * 1e18) / osloReserve : 0;
        emit Swapped(recipient, true, usdtAmount, osloAmount, newPrice);
        emit PriceUpdated(newPrice);
    }

    // ─── Public Swap Functions ─────────────────────────────────────────

    /// @notice Swap USDT for OSLO — restricted to InvestmentEngine only.
    /// @dev Regular users cannot swap USDT→OSLO. Only the InvestmentEngine
    ///      may use this for protocol operations (yield auto-buy uses swapYieldForOSLO).
    /// @param usdtAmount Amount of USDT to swap
    /// @param minOsloAmount Minimum OSLO to receive (slippage protection)
    /// @return osloAmount Amount of OSLO received
    function swapUSDTForOSLO(uint256 usdtAmount, uint256 minOsloAmount)
        external onlyInvestmentEngine nonReentrant returns (uint256 osloAmount) {
        if (usdtAmount == 0) revert ZeroAmount();
        if (usdtReserve == 0 || osloReserve == 0) revert InsufficientReserve();

        osloAmount = (usdtAmount * osloReserve) / (usdtReserve + usdtAmount);

        if (osloAmount == 0 || osloAmount < minOsloAmount) revert SlippageExceeded();

        usdt.safeTransferFrom(msg.sender, address(this), usdtAmount);
        osloToken.safeTransfer(msg.sender, osloAmount);

        usdtReserve += usdtAmount;
        osloReserve -= osloAmount;

        totalVolumeUSDT += usdtAmount;
        totalSwaps++;

        uint256 newPrice = osloReserve > 0 ? (usdtReserve * 1e18) / osloReserve : 0;
        emit Swapped(msg.sender, true, usdtAmount, osloAmount, newPrice);
        emit PriceUpdated(newPrice);
    }

    /// @notice Swap OSLO for USDT
    /// @dev V3: 10% sell tax applied in OSLOToken._update → OSLO burned.
    ///      DEX receives 90% of OSLO but pays USDT for 100% of the declared amount.
    ///      This means the 10% fee USDT stays in DEX as additional LP.
    ///      No additional DEX-level fee deduction from user's USDT.
    /// @param osloAmount Amount of OSLO to swap
    /// @param minUSDTAmount Minimum USDT to receive (slippage protection)
    /// @return usdtAmount Amount of USDT received
    function swapOSLOForUSDT(uint256 osloAmount, uint256 minUSDTAmount) external nonReentrant returns (uint256 usdtAmount) {
        if (osloAmount == 0) revert ZeroAmount();
        if (usdtReserve == 0 || osloReserve == 0) revert InsufficientReserve();

        // Transfer OSLO from user to DEX — OSLOToken._update burns 10% as sell tax.
        // DEX receives ~90% of osloAmount.
        uint256 osloBefore = osloToken.balanceOf(address(this));
        osloToken.safeTransferFrom(msg.sender, address(this), osloAmount);
        uint256 osloReceived = osloToken.balanceOf(address(this)) - osloBefore;

        // Calculate USDT output using the DECLARED osloAmount (before tax).
        // This ensures fair pricing and the fee's USDT value stays in DEX as LP.
        usdtAmount = (osloAmount * usdtReserve) / (osloReserve + osloAmount);

        if (usdtAmount == 0 || usdtAmount < minUSDTAmount) revert SlippageExceeded();
        if (usdtAmount > usdtReserve) revert InsufficientReserve();

        // Update reserves:
        // - USDT: full usdtAmount leaves DEX (10% fee USDT effectively stays as LP
        //   because DEX receives only 90% OSLO but pays 100% USDT)
        // - OSLO: only add tokens actually received (~90%)
        usdtReserve -= usdtAmount;
        osloReserve += osloReceived;

        // Transfer USDT to user — no additional fee deduction (10% already paid via token burn)
        usdt.safeTransfer(msg.sender, usdtAmount);

        totalVolumeUSDT += usdtAmount;
        totalSwaps++;

        uint256 newPrice = osloReserve > 0 ? (usdtReserve * 1e18) / osloReserve : 0;
        emit Swapped(msg.sender, false, osloAmount, usdtAmount, newPrice);
        emit PriceUpdated(newPrice);
    }

    // ─── View Functions ─────────────────────────────────────────────────

    /// @notice Get current OSLO price in USDT
    /// @return Price in USDT per OSLO (18 decimals)
    function getPrice() external view returns (uint256) {
        if (osloReserve == 0 || usdtReserve == 0) return 0;
        return (usdtReserve * 1e18) / osloReserve;
    }

    /// @notice Calculate OSLO output for a given USDT input at current price
    /// @param usdtAmount Input USDT amount
    /// @return Expected OSLO output
    function getUSDTForOSLOOutput(uint256 usdtAmount) external view returns (uint256) {
        if (usdtAmount == 0 || usdtReserve == 0 || osloReserve == 0) return 0;
        return (usdtAmount * osloReserve) / (usdtReserve + usdtAmount);
    }

    /// @notice Calculate USDT output for a given OSLO input at current price
    /// @param osloAmount Input OSLO amount
    /// @return Expected USDT output
    function getOSLOForUSDTOutput(uint256 osloAmount) external view returns (uint256) {
        if (osloAmount == 0 || usdtReserve == 0 || osloReserve == 0) return 0;
        uint256 usdtAmount = (osloAmount * usdtReserve) / (osloReserve + osloAmount);
        if (usdtAmount > usdtReserve) return 0;
        return usdtAmount;
    }

    /// @notice Receive OSLO from InvestmentEngine to replenish DEX reserves.
    /// @dev Called by InvestmentEngine when DEX OSLO is depleted from deposits.
    /// @param osloAmount Amount of OSLO to add to reserves
    function replenishOsloReserve(uint256 osloAmount) external onlyInvestmentEngine {
        if (osloAmount == 0) revert ZeroAmount();
        osloToken.safeTransferFrom(msg.sender, address(this), osloAmount);
        osloReserve += osloAmount;
    }

    /// @notice Get reserves
    /// @return _usdtRes USDT reserve
    /// @return _osloRes OSLO reserve
    function getReserves() external view returns (uint256 _usdtRes, uint256 _osloRes) {
        return (usdtReserve, osloReserve);
    }
}

contracts/OSLOInvestmentEngine.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./libraries/OSLOConstants.sol";
import "./interfaces/IInvestmentEngine.sol";
import "./interfaces/ITreasury.sol";
import "./interfaces/IReferral.sol";
import "./interfaces/IRankSystem.sol";
import "./interfaces/IOSLODEX.sol";


/// @title OSLOInvestmentEngine
/// @notice Core staking contract V2: USDT deposits, ranged tier yields, lifetime 0.45% rate, combined 3X cap.
/// @dev No deposit fee. USDT flows to DEX for liquidity. OSLO paid as rewards from contract reserve.
contract OSLOInvestmentEngine is IInvestmentEngine, ReentrancyGuard {
    using SafeERC20 for IERC20;

    // ─── Structs ────────────────────────────────────────────────────────

    struct Deposit {
        uint256 amount;          // USDT principal amount
        uint256 tier;            // Tier 1-4
        uint256 dailyRate;       // Effective daily rate in bp (cached at deposit time)
        uint256 depositTime;     // Timestamp of deposit
        uint256 lastClaimTime;   // Last time rewards were claimed
        uint256 totalClaimed;    // Total USDT-equivalent rewards claimed
        uint256 maxReturn;       // 3X of principal (precomputed)
        bool active;             // Whether this deposit is still yielding
    }

    struct UserInfo {
        uint256 totalActiveDeposit;  // Sum of all active deposit principals (USDT)
        uint256 depositCount;        // Number of deposits
        uint256 totalCombinedEarnings; // Daily yield + level income + rank bonus (USDT-equivalent)
    }

    // ─── State ──────────────────────────────────────────────────────────

    IERC20 public immutable usdt;
    IERC20 public immutable osloToken;
    uint256 public immutable launchTimestamp;
    address public osloDex;          // OSLODEX — handles USDT↔OSLO conversions
    address public treasury;
    address public referral;
    address public rankSystem;
    address public admin;
    address public timelock;
    bool public setupComplete;
    bool public depositsPaused;      // Emergency pause for new deposits only
    uint256 public minClaimThreshold = 1 * 1e18; // $1 USDT minimum to claim (settable by timelock)

    mapping(address => Deposit[]) public userDeposits;
    mapping(address => UserInfo) public users;

    uint256 public totalDeposited;
    uint256 public totalWithdrawn;
    uint256 public totalRewardsPaid;

    // ─── Events ─────────────────────────────────────────────────────────
    event Deposited(address indexed user, uint256 amount, uint256 tier, uint256 dailyRate, uint256 depositIndex);
    event RewardsClaimed(address indexed user, uint256 usdtReward, uint256 osloAmount, uint256 depositIndex);
    event PrincipalWithdrawn(address indexed user, uint256 netPrincipal, uint256 depositIndex);
    event EarlyExited(address indexed user, uint256 amountReturned, uint256 feeDeducted, uint256 yieldDeducted, uint256 depositIndex);
    event DepositsPaused(bool paused);
    event CombinedCapReached(address indexed user);
    event CombinedEarningsUpdated(address indexed user, uint256 totalCombined);
    event ReferralUpdated(address indexed oldReferral, address indexed newReferral);

    // ─── Errors ─────────────────────────────────────────────────────────
    error OnlyAdmin();
    error OnlyTimelock();
    error OnlyReferral();
    error OnlyRankSystem();
    error SetupAlreadyComplete();
    error NotConfigured();
    error DepositTooLow();
    error DepositTooHigh();
    error DepositsPausedError();
    error InvalidDeposit();
    error DepositCapped();
    error NothingToClaim();
    error BelowWithdrawalThreshold();
    error DEXNotPriced();
    error ZeroAddress();
    error InsufficientOsloReserve();
    error NotInEarlyExitPeriod();
    error InsufficientUSDTReserve();

    modifier onlyAdmin() {
        if (msg.sender != admin) revert OnlyAdmin();
        _;
    }

    modifier onlyTimelock() {
        if (msg.sender != timelock) revert OnlyTimelock();
        _;
    }

    modifier onlyReferral() {
        if (msg.sender != referral) revert OnlyReferral();
        _;
    }

    modifier onlyRankSystem() {
        if (msg.sender != rankSystem) revert OnlyRankSystem();
        _;
    }

    constructor(address _usdt, address _osloToken, uint256 _launchTimestamp) {
        if (_usdt == address(0) || _osloToken == address(0)) revert ZeroAddress();
        usdt = IERC20(_usdt);
        osloToken = IERC20(_osloToken);
        launchTimestamp = _launchTimestamp;
        admin = msg.sender;
    }

    // ─── Setup ──────────────────────────────────────────────────────────

    function configure(
        address _treasury,
        address _referral,
        address _rankSystem,
        address _osloDex,
        address _timelock
    ) external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        if (_osloDex == address(0)) revert ZeroAddress();
        treasury = _treasury;
        referral = _referral;
        rankSystem = _rankSystem;
        osloDex = _osloDex;
        timelock = _timelock;
    }

    function completeSetup() external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        if (treasury == address(0)) revert NotConfigured();
        setupComplete = true;
        admin = address(0);
    }

    /// @notice Emergency pause for new deposits only. Only callable by Timelock.
    function setDepositsPaused(bool _paused) external onlyTimelock {
        depositsPaused = _paused;
        emit DepositsPaused(_paused);
    }

    /// @notice Update referral contract address. Only callable by Timelock.
    /// @dev Used when redeploying the referral contract with new features.
    function setReferral(address _referral) external onlyTimelock {
        emit ReferralUpdated(referral, _referral);
        referral = _referral;
    }

    /// @notice Set the minimum claim threshold in USDT (18 decimals). Only callable by Timelock.
    /// @param _threshold New minimum threshold (e.g. 1 * 1e18 = $1)
    function setMinClaimThreshold(uint256 _threshold) external onlyTimelock {
        minClaimThreshold = _threshold;
    }

    // ─── Core Functions ─────────────────────────────────────────────────

    /// @notice Deposit USDT into the investment engine. No deposit fee — full amount staked.
    /// @dev USDT flows to DEX as liquidity; equivalent OSLO pulled from DEX to contract reserve.
    /// @param amount Amount of USDT to deposit
    function deposit(uint256 amount) external nonReentrant {
        if (depositsPaused) revert DepositsPausedError();
        if (amount < OSLOConstants.TIER1_MIN) revert DepositTooLow();
        if (amount > OSLOConstants.MAX_DEPOSIT_PER_TX) revert DepositTooHigh();
        if (osloDex == address(0)) revert NotConfigured();

        // Transfer USDT from user to this contract
        usdt.safeTransferFrom(msg.sender, address(this), amount);

        // Ensure DEX has sufficient OSLO reserve for this deposit.
        // DEX OSLO is consumed by every deposit but never replenished by sells
        // (tax routing sends 70% to IE + 30% burn, 0% to DEX).
        // InvestmentEngine holds 11M OSLO reserve — auto-refill DEX as needed.
        {
            uint256 dexOsloBalance = osloToken.balanceOf(osloDex);
            uint256 estimatedOsloNeeded;
            (uint256 dexUsdt, uint256 dexOslo) = IOSLODEX(osloDex).getReserves();
            if (dexUsdt > 0 && dexOslo > 0) {
                estimatedOsloNeeded = (amount * dexOslo) / (dexUsdt + amount);
            } else {
                estimatedOsloNeeded = amount;
            }
            uint256 minBuffer = 1000 * 1e18; // 1,000 OSLO minimum buffer
            if (dexOsloBalance < estimatedOsloNeeded + minBuffer) {
                uint256 shortfall = (estimatedOsloNeeded + minBuffer) - dexOsloBalance;
                uint256 ieOsloBalance = osloToken.balanceOf(address(this));
                if (ieOsloBalance >= shortfall) {
                    osloToken.forceApprove(osloDex, shortfall);
                    IOSLODEX(osloDex).replenishOsloReserve(shortfall);
                }
            }
        }

        // Approve and send USDT to DEX, receive OSLO in return
        usdt.forceApprove(osloDex, amount);
        uint256 osloReceived = IOSLODEX(osloDex).processDeposit(amount);
        // OSLO is now held by this contract as reserve (transferred by DEX)

        // Determine tier and daily rate based on amount
        uint256 tier = _getTier(amount);
        uint256 dailyRate = _getDailyRate(amount);

        // Create deposit record
        uint256 maxReturn = amount * OSLOConstants.RETURN_CAP_MULTIPLIER;
        userDeposits[msg.sender].push(Deposit({
            amount: amount,
            tier: tier,
            dailyRate: dailyRate,
            depositTime: block.timestamp,
            lastClaimTime: block.timestamp,
            totalClaimed: 0,
            maxReturn: maxReturn,
            active: true
        }));

        users[msg.sender].totalActiveDeposit += amount;
        users[msg.sender].depositCount++;
        totalDeposited += amount;

        // Update referral levels
        if (referral != address(0)) {
            IReferral(referral).checkAndUnlockLevels(msg.sender);
        }

        // Record turnover for rank system (for all uplines)
        if (rankSystem != address(0) && referral != address(0)) {
            _recordTurnoverForUplines(msg.sender, amount);
        }

        emit Deposited(msg.sender, amount, tier, dailyRate, userDeposits[msg.sender].length - 1);
    }

    /// @notice Claim accrued rewards from a specific deposit.
    /// @dev V3: Yield is calculated in USDT. No withdrawal fee — full yield is auto-bought
    ///      into OSLO at the DEX spot rate and sent to the investor.
    ///      OSLO is paid from the contract's reserve (accumulated from deposit swaps).
    /// @param depositIndex Index of the deposit in user's deposits array
    function claimRewards(uint256 depositIndex) external nonReentrant {
        Deposit storage dep = _getActiveDeposit(msg.sender, depositIndex);

        uint256 pendingUSDT = _calculatePendingRewards(msg.sender, dep);
        if (pendingUSDT == 0) revert NothingToClaim();

        // Minimum withdrawal threshold check (settable by timelock, default $1)
        if (pendingUSDT < minClaimThreshold) revert BelowWithdrawalThreshold();

        // Combined 3X cap check
        uint256 maxCombined = dep.amount * OSLOConstants.RETURN_CAP_MULTIPLIER;
        UserInfo storage userInfo = users[msg.sender];
        uint256 remainingCap = maxCombined > userInfo.totalCombinedEarnings
            ? maxCombined - userInfo.totalCombinedEarnings
            : 0;

        if (remainingCap == 0) {
            dep.active = false;
            emit CombinedCapReached(msg.sender);
            revert DepositCapped();
        }

        if (pendingUSDT > remainingCap) {
            pendingUSDT = remainingCap;
        }

        // V3: No withdrawal fee — full yield is auto-bought into OSLO.
        // Convert pending USDT yield to OSLO at DEX spot price (tax-free).
        uint256 osloAmount = IOSLODEX(osloDex).getUSDTForOSLOOutput(pendingUSDT);
        if (osloAmount == 0) revert DEXNotPriced();

        // Verify contract has enough OSLO reserve
        if (osloToken.balanceOf(address(this)) < osloAmount) revert InsufficientOsloReserve();

        // Update accounting BEFORE external call
        dep.totalClaimed += pendingUSDT;
        dep.lastClaimTime = block.timestamp;
        userInfo.totalCombinedEarnings += pendingUSDT;
        totalRewardsPaid += pendingUSDT;

        // Check if cap reached
        if (dep.totalClaimed >= dep.maxReturn) {
            dep.active = false;
            emit CombinedCapReached(msg.sender);
        }

        // Auto-buy: send OSLO tokens to investor (from contract reserve).
        // Frontend displays this as "$X USDT yield → Y OSLO at DEX rate".
        osloToken.safeTransfer(msg.sender, osloAmount);

        // Distribute referral commission — yield on yield
        // Commission is based on the full yield (pendingUSDT), not just a fraction.
        // Upline receives percentage of downline's yield earnings:
        //   L1: 30%, L2: 20%, L3-L10: 1%, L11-L15: 0.50%, L16-L20: 0.25%
        if (referral != address(0)) {
            if (pendingUSDT > 0) {
                IReferral(referral).distributeReferralCommission(msg.sender, pendingUSDT);
            }
        }

        emit RewardsClaimed(msg.sender, pendingUSDT, osloAmount, depositIndex);
        emit CombinedEarningsUpdated(msg.sender, userInfo.totalCombinedEarnings);
    }



    /// @notice Early exit — withdraw within 10-day window. Returns USDT directly.
    /// @dev Deducts 10% early exit fee + all accrued yield. Net returned in USDT, not tokens.
    ///      Available only within EARLY_EXIT_PERIOD (10 days) from deposit.
    ///      Example: $100 deposit, 4 days elapsed, $4 yield earned
    ///               → Deduct $4 (yield) + $10 (10% fee) = $14
    ///               → Return $86 USDT to investor
    /// @param depositIndex Index of the deposit
    function earlyExit(uint256 depositIndex) external nonReentrant {
        Deposit storage dep = _getActiveDeposit(msg.sender, depositIndex);

        // Must be within 10-day early exit window
        if (block.timestamp > dep.depositTime + OSLOConstants.EARLY_EXIT_PERIOD) {
            revert NotInEarlyExitPeriod();
        }

        uint256 principal = dep.amount;

        // Calculate accrued yield (same formula as _calculatePendingRewards)
        uint256 accruedYield = _calculatePendingRewards(msg.sender, dep);

        // 10% early exit fee on principal
        uint256 exitFee = (principal * OSLOConstants.EARLY_EXIT_FEE_BP) / OSLOConstants.BASIS_POINTS;

        // Total deductions = accrued yield + 10% fee
        uint256 totalDeductions = accruedYield + exitFee;

        // Net return to investor
        uint256 netReturn = principal > totalDeductions ? principal - totalDeductions : 0;

        // Mark deposit as inactive
        dep.active = false;
        users[msg.sender].totalActiveDeposit -= principal;
        totalWithdrawn += principal;

        // Update referral levels
        if (referral != address(0)) {
            IReferral(referral).checkAndUnlockLevels(msg.sender);
        }

        // Return net amount in USDT directly (not tokens)
        if (netReturn > 0) {
            // Try to get USDT from contract balance first (from fees)
            uint256 usdtBalance = usdt.balanceOf(address(this));
            if (usdtBalance >= netReturn) {
                usdt.safeTransfer(msg.sender, netReturn);
            } else {
                // Fallback: pull from DEX liquidity
                if (usdtBalance > 0) {
                    usdt.safeTransfer(msg.sender, usdtBalance);
                    netReturn -= usdtBalance;
                }
                uint256 osloAmount = IOSLODEX(osloDex).getUSDTForOSLOOutput(netReturn);
                if (osloAmount > 0 && osloToken.balanceOf(address(this)) >= osloAmount) {
                    osloToken.forceApprove(osloDex, osloAmount);
                    IOSLODEX(osloDex).processWithdrawal(osloAmount, msg.sender);
                }
            }
        }

        emit EarlyExited(msg.sender, netReturn, exitFee, accruedYield, depositIndex);
    }

    /// @notice Check if a deposit is within the early exit period
    /// @param user Address of the investor
    /// @param depositIndex Index of the deposit
    /// @return bool True if early exit is available
    function isInEarlyExitPeriod(address user, uint256 depositIndex) external view returns (bool) {
        if (depositIndex >= userDeposits[user].length) return false;
        Deposit storage dep = userDeposits[user][depositIndex];
        if (!dep.active) return false;
        return block.timestamp <= dep.depositTime + OSLOConstants.EARLY_EXIT_PERIOD;
    }

    /// @notice Get the early exit amount breakdown for a deposit
    /// @param user Address of the investor
    /// @param depositIndex Index of the deposit
    /// @return principal The original deposit amount
    /// @return accruedYield Yield earned so far
    /// @return exitFee 10% early exit fee
    /// @return netReturn Amount investor would receive in USDT
    function getEarlyExitAmount(address user, uint256 depositIndex)
        external view returns (uint256 principal, uint256 accruedYield, uint256 exitFee, uint256 netReturn)
    {
        if (depositIndex >= userDeposits[user].length) return (0, 0, 0, 0);
        Deposit storage dep = userDeposits[user][depositIndex];
        if (!dep.active || block.timestamp > dep.depositTime + OSLOConstants.EARLY_EXIT_PERIOD) {
            return (0, 0, 0, 0);
        }

        principal = dep.amount;
        accruedYield = _calculatePendingRewards(user, dep);
        exitFee = (principal * OSLOConstants.EARLY_EXIT_FEE_BP) / OSLOConstants.BASIS_POINTS;
        uint256 totalDeductions = accruedYield + exitFee;
        netReturn = principal > totalDeductions ? principal - totalDeductions : 0;
    }

    // ─── Cross-Contract Notifications ───────────────────────────────────

    /// @notice Called by OSLOReferral when distributing level income to track combined 3X cap.
    /// @param user The user receiving level income
    /// @param amount USDT-equivalent amount of commission earned
    function notifyLevelIncome(address user, uint256 amount) external override onlyReferral {
        users[user].totalCombinedEarnings += amount;
        emit CombinedEarningsUpdated(user, users[user].totalCombinedEarnings);
    }

    /// @notice Called by OSLORankSystem when paying rank bonuses to track combined 3X cap.
    /// @param user The user receiving rank bonus
    /// @param amount USDT-equivalent amount of bonus earned
    function notifyRankBonus(address user, uint256 amount) external override onlyRankSystem {
        users[user].totalCombinedEarnings += amount;
        emit CombinedEarningsUpdated(user, users[user].totalCombinedEarnings);
    }

    // ─── View Functions ─────────────────────────────────────────────────

    function getActiveDeposit(address user) external view override returns (uint256) {
        return users[user].totalActiveDeposit;
    }

    function getUserTier(address user) external view override returns (uint256) {
        if (users[user].totalActiveDeposit == 0) return 0;
        return _getTier(users[user].totalActiveDeposit);
    }

    function getDepositCount(address user) external view returns (uint256) {
        return userDeposits[user].length;
    }

    function getCombinedEarnings(address user) external view returns (uint256) {
        return users[user].totalCombinedEarnings;
    }

    function getPendingRewards(address user, uint256 depositIndex) external view returns (uint256 pendingUSDT) {
        if (depositIndex >= userDeposits[user].length) return 0;
        Deposit storage dep = userDeposits[user][depositIndex];
        if (!dep.active) return 0;
        return _calculatePendingRewards(user, dep);
    }

    // ─── Internal Functions ─────────────────────────────────────────────

    function _getActiveDeposit(address user, uint256 index) internal view returns (Deposit storage) {
        if (index >= userDeposits[user].length) revert InvalidDeposit();
        Deposit storage dep = userDeposits[user][index];
        if (!dep.active) revert DepositCapped();
        return dep;
    }

    /// @dev Determine tier (1-4) based on USDT amount
    function _getTier(uint256 amount) internal pure returns (uint256) {
        if (amount >= OSLOConstants.TIER4_MIN) return 4;
        if (amount >= OSLOConstants.TIER3_MIN) return 3;
        if (amount >= OSLOConstants.TIER2_MIN) return 2;
        return 1;
    }

    /// @notice Get the daily rate (in bp) for a given USDT amount.
    /// @dev Before 3 months: tier-based ranged rate (linear interpolation within tier).
    ///      After 3 months: flat 0.45% lifetime rate for all stakes.
    function _getDailyRate(uint256 amount) internal view returns (uint256) {
        uint256 elapsed = block.timestamp - launchTimestamp;

        // After 3 months: lifetime 0.45% rate applies to ALL stakes (new and re-stakes)
        if (elapsed >= OSLOConstants.LIFETIME_RATE_START) {
            return OSLOConstants.LIFETIME_RATE;
        }

        uint256 tier = _getTier(amount);

        // Linear interpolation within tier's min/max rate range
        if (tier == 1) {
            return _interpolate(amount, OSLOConstants.TIER1_MIN, OSLOConstants.TIER1_MAX,
                OSLOConstants.TIER1_RATE_MIN, OSLOConstants.TIER1_RATE_MAX);
        }
        if (tier == 2) {
            return _interpolate(amount, OSLOConstants.TIER2_MIN, OSLOConstants.TIER2_MAX,
                OSLOConstants.TIER2_RATE_MIN, OSLOConstants.TIER2_RATE_MAX);
        }
        if (tier == 3) {
            return _interpolate(amount, OSLOConstants.TIER3_MIN, OSLOConstants.TIER3_MAX,
                OSLOConstants.TIER3_RATE_MIN, OSLOConstants.TIER3_RATE_MAX);
        }
        // Tier 4: $5,000+ — interpolate up to implicit max ($50,000)
        uint256 cappedAmount = amount > OSLOConstants.TIER4_IMPLICIT_MAX
            ? OSLOConstants.TIER4_IMPLICIT_MAX : amount;
        return _interpolate(cappedAmount, OSLOConstants.TIER4_MIN, OSLOConstants.TIER4_IMPLICIT_MAX,
            OSLOConstants.TIER4_RATE_MIN, OSLOConstants.TIER4_RATE_MAX);
    }

    /// @dev Linear interpolation: rate = minRate + (amount - minAmt) * (maxRate - minRate) / (maxAmt - minAmt)
    function _interpolate(
        uint256 amount,
        uint256 minAmt,
        uint256 maxAmt,
        uint256 minRate,
        uint256 maxRate
    ) internal pure returns (uint256) {
        if (maxAmt <= minAmt) return minRate;
        uint256 rateRange = maxRate - minRate;
        uint256 amtRange = maxAmt - minAmt;
        return minRate + ((amount - minAmt) * rateRange) / amtRange;
    }

    function _calculatePendingRewards(address user, Deposit storage dep) internal view returns (uint256 pendingUSDT) {
        if (!dep.active) return 0;

        uint256 timeElapsed = block.timestamp - dep.lastClaimTime;
        if (timeElapsed == 0) return 0;

        // Re-compute daily rate (may have changed to lifetime rate if 3 months passed)
        uint256 effectiveRate = _getDailyRate(dep.amount);
        // Use the better of the cached rate or current rate (lifetime rate may be lower)
        if (block.timestamp - launchTimestamp >= OSLOConstants.LIFETIME_RATE_START) {
            effectiveRate = OSLOConstants.LIFETIME_RATE;
        }

        // pending = (depositAmount * rate * timeElapsed) / (1 day * BASIS_POINTS)
        pendingUSDT = (dep.amount * effectiveRate * timeElapsed) / (1 days * OSLOConstants.BASIS_POINTS);

        // 3X per-deposit cap check
        uint256 remaining = dep.maxReturn > dep.totalClaimed ? dep.maxReturn - dep.totalClaimed : 0;
        if (pendingUSDT > remaining) {
            pendingUSDT = remaining;
        }
    }

    function _recordTurnoverForUplines(address user, uint256 amount) internal {
        if (referral == address(0) || rankSystem == address(0)) return;
        address current = user;
        for (uint256 i = 0; i < OSLOConstants.MAX_REFERRAL_LEVELS; i++) {
            address upline = IReferral(referral).getReferrer(current);
            if (upline == address(0)) break;
            IRankSystem(rankSystem).recordTurnover(upline, current, amount);
            current = upline;
        }
    }
}

contracts/OSLOLiquidityManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./libraries/OSLOConstants.sol";
import "./interfaces/ILiquidityManager.sol";
import "./interfaces/IOSLODEX.sol";

/// @title OSLOLiquidityManager
/// @notice Manages liquidity for OSLO DEX. Protocol-controlled liquidity only.
/// @dev V2: Routes funds to OSLODEX for USDT/OSLO trading.
contract OSLOLiquidityManager is ILiquidityManager, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable usdt;
    IERC20 public immutable osloToken;
    
    address public oslodex; // Custom OSLO DEX contract

    address public admin;
    address public timelock;
    bool public setupComplete;

    uint256 public totalLiquidityAdded;

    // ─── Events ─────────────────────────────────────────────────────────
    event LiquidityAdded(uint256 usdtAmount, uint256 osloAmount);
    event TokensRescued(address indexed token, uint256 amount);

    // ─── Errors ─────────────────────────────────────────────────────────
    error OnlyAdmin();
    error OnlyTimelock();
    error SetupAlreadyComplete();
    error ZeroAmount();
    error ZeroAddress();
    error CannotRescueProtocolTokens();

    modifier onlyAdmin() {
        if (msg.sender != admin) revert OnlyAdmin();
        _;
    }

    modifier onlyTimelock() {
        if (msg.sender != timelock) revert OnlyTimelock();
        _;
    }

    constructor(address _usdt, address _osloToken) {
        if (_usdt == address(0) || _osloToken == address(0))
            revert ZeroAddress();
        usdt = IERC20(_usdt);
        osloToken = IERC20(_osloToken);
        admin = msg.sender;
    }

    function configure(address _timelock, address _oslodex) external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        timelock = _timelock;
        oslodex = _oslodex;
    }

    function completeSetup() external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        setupComplete = true;
        admin = address(0);
    }

    // ─── Core Functions ─────────────────────────────────────────────────

    /// @notice Set up initial liquidity pool. Called once during deployment.
    /// @dev Transfers USDT and OSLO to OSLODEX contract.
    function addInitialLiquidity(uint256 usdtAmount) external onlyAdmin {
        if (usdtAmount == 0) revert ZeroAmount();
        uint256 osloAmount = osloToken.balanceOf(address(this));
        if (osloAmount == 0) revert ZeroAmount();
        
        // Approve OSLODEX to pull tokens
        usdt.forceApprove(oslodex, usdtAmount);
        osloToken.forceApprove(oslodex, osloAmount);
        
        // Add liquidity to OSLODEX
        IOSLODEX(oslodex).addInitialLiquidity(usdtAmount, osloAmount);
        
        totalLiquidityAdded += usdtAmount;
        emit LiquidityAdded(usdtAmount, osloAmount);
    }

    /// @notice Add liquidity from fee distributions. Routes to OSLODEX.
    function addLiquidityFromFees(uint256 usdtAmount) external override nonReentrant {
        if (usdtAmount == 0) revert ZeroAmount();
        
        // Approve OSLODEX to pull USDT
        usdt.forceApprove(oslodex, usdtAmount);
        
        // Add liquidity to OSLODEX
        IOSLODEX(oslodex).addLiquidityFromFees(usdtAmount);
        
        totalLiquidityAdded += usdtAmount;
        emit LiquidityAdded(usdtAmount, 0);
    }

    /// @notice Rescue accidentally sent tokens. Only by DAO Timelock.
    function rescueERC20(address token, uint256 amount) external onlyTimelock {
        if (token == address(usdt) || token == address(osloToken))
            revert CannotRescueProtocolTokens();
        IERC20(token).safeTransfer(timelock, amount);
        emit TokensRescued(token, amount);
    }

    // ─── View Functions ─────────────────────────────────────────────

    /// @notice Get current OSLO price from OSLODEX
    /// @return Price in USDT per OSLO (18 decimals)
    function getOSLOPrice() external view returns (uint256) {
        return IOSLODEX(oslodex).getPrice();
    }

    /// @notice Get DEX reserves
    /// @return _usdtRes USDT reserve in DEX
    /// @return _osloRes OSLO reserve in DEX
    function getDEXReserves() external view returns (uint256 _usdtRes, uint256 _osloRes) {
        return IOSLODEX(oslodex).getReserves();
    }
}

contracts/OSLORankSystem.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./libraries/OSLOConstants.sol";
import "./interfaces/IRankSystem.sol";
import "./interfaces/IReferral.sol";
import "./interfaces/IInvestmentEngine.sol";

/// @title OSLORankSystem
/// @notice Calculates weekly team turnover and distributes progressive rank bonuses in USDT.
/// @dev V2: Bonuses paid in USDT. Notifies InvestmentEngine for combined 3X cap tracking.
contract OSLORankSystem is IRankSystem, ReentrancyGuard {
    using SafeERC20 for IERC20;

    // ─── State ──────────────────────────────────────────────────────────

    IERC20 public immutable usdt;
    address public investmentEngine;
    address public referral;
    address public admin;
    address public timelock;
    bool public setupComplete;

    /// @notice Weekly turnover per user per weekId: weeklyTurnover[user][weekId]
    mapping(address => mapping(uint256 => uint256)) public weeklyTurnoverData;

    /// @notice Per-leg weekly turnover: legTurnover[user][weekId][legAddress]
    mapping(address => mapping(uint256 => mapping(address => uint256))) public legTurnover;

    /// @notice Whether a user has claimed their bonus for a given week
    mapping(address => mapping(uint256 => bool)) public weekBonusClaimed;

    /// @notice Rank bonus pool balance available for distribution
    uint256 public bonusPoolBalance;

    /// @notice Total bonuses distributed all-time (USDT)
    uint256 public totalBonusesDistributed;

    /// @notice Genesis timestamp for week epoch calculation (set to first Monday UTC)
    uint256 public immutable genesisTimestamp;

    // ─── Events ─────────────────────────────────────────────────────────
    event RankAchieved(address indexed user, uint256 rank, uint256 weekId, uint256 turnover);
    event RankBonusClaimed(address indexed user, uint256 amount, uint256 weekId);
    event BonusPoolFunded(uint256 amount);
    event TurnoverRecorded(address indexed user, uint256 amount, uint256 weekId);

    // ─── Errors ─────────────────────────────────────────────────────────
    error OnlyAdmin();
    error OnlyTimelock();
    error SetupAlreadyComplete();
    error AlreadyClaimed();
    error NoBonus();
    error InsufficientBonusPool();
    error CurrentWeekNotClaimable();
    error ZeroAddress();

    modifier onlyAdmin() {
        if (msg.sender != admin) revert OnlyAdmin();
        _;
    }

    modifier onlyTimelock() {
        if (msg.sender != timelock) revert OnlyTimelock();
        _;
    }

    constructor(address _usdt) {
        if (_usdt == address(0)) revert ZeroAddress();
        usdt = IERC20(_usdt);
        admin = msg.sender;
        // Set genesis to a fixed Monday 00:00 UTC (Jan 1, 2024 was a Monday)
        genesisTimestamp = 1704067200; // 2024-01-01 00:00:00 UTC (Monday)
    }

    // ─── Setup ──────────────────────────────────────────────────────────

    function configure(address _investmentEngine, address _referral, address _timelock) external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        investmentEngine = _investmentEngine;
        referral = _referral;
        timelock = _timelock;
    }

    function completeSetup() external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        setupComplete = true;
        admin = address(0);
    }

    /// @notice Update the InvestmentEngine address. Only callable by Timelock after setup.
    /// @dev Used when redeploying InvestmentEngine with new features.
    function setInvestmentEngine(address _investmentEngine) external onlyTimelock {
        investmentEngine = _investmentEngine;
    }

    // ─── Core Functions ─────────────────────────────────────────────────

    /// @notice Record turnover for a user in the current week. Called by InvestmentEngine.
    /// @param leg The direct child address identifying which referral leg this turnover belongs to
    function recordTurnover(address user, address leg, uint256 amount) external override {
        uint256 weekId = getCurrentWeekId();
        weeklyTurnoverData[user][weekId] += amount;
        legTurnover[user][weekId][leg] += amount;
        emit TurnoverRecorded(user, amount, weekId);
    }

    /// @notice Receive USDT into the bonus pool from Treasury
    function receiveBonusPool(uint256 amount) external override {
        usdt.safeTransferFrom(msg.sender, address(this), amount);
        bonusPoolBalance += amount;
        emit BonusPoolFunded(amount);
    }

    /// @notice Claim rank bonus for a completed week. Paid in USDT.
    /// @dev Can only claim for past weeks, not the current one. Requires 40/60 leg ratio qualification.
    function claimRankBonus() external override nonReentrant {
        uint256 currentWeek = getCurrentWeekId();
        // Claim for the most recent completed week
        uint256 claimWeek = currentWeek - 1;
        if (claimWeek == 0) revert NoBonus();

        if (weekBonusClaimed[msg.sender][claimWeek]) revert AlreadyClaimed();

        // Must satisfy 40/60 leg ratio to qualify
        if (!_isRankQualified(msg.sender, claimWeek)) revert NoBonus();

        uint256 turnover = weeklyTurnoverData[msg.sender][claimWeek];
        uint256 rank = _getRankFromTurnover(turnover);
        if (rank == 0) revert NoBonus();

        uint256 bonusBP = _getRankBonusBP(rank);
        uint256 bonus = (turnover * bonusBP) / OSLOConstants.BASIS_POINTS;

        if (bonus == 0) revert NoBonus();
        if (bonus > bonusPoolBalance) revert InsufficientBonusPool();

        weekBonusClaimed[msg.sender][claimWeek] = true;
        bonusPoolBalance -= bonus;
        totalBonusesDistributed += bonus;

        // Pay bonus in USDT
        usdt.safeTransfer(msg.sender, bonus);

        // Notify InvestmentEngine for combined 3X cap tracking
        if (investmentEngine != address(0)) {
            IInvestmentEngine(investmentEngine).notifyRankBonus(msg.sender, bonus);
        }

        emit RankAchieved(msg.sender, rank, claimWeek, turnover);
        emit RankBonusClaimed(msg.sender, bonus, claimWeek);
    }

    // ─── View Functions ─────────────────────────────────────────────────

    function getCurrentWeekId() public view override returns (uint256) {
        return (block.timestamp - genesisTimestamp) / OSLOConstants.WEEK_DURATION + 1;
    }

    function getCurrentRank(address user) external view override returns (uint256) {
        uint256 weekId = getCurrentWeekId();
        if (!_isRankQualified(user, weekId)) return 0;
        uint256 turnover = weeklyTurnoverData[user][weekId];
        return _getRankFromTurnover(turnover);
    }

    function getWeeklyTurnover(address user, uint256 weekId) external view override returns (uint256) {
        return weeklyTurnoverData[user][weekId];
    }

    function getLegTurnover(address user, uint256 weekId, address leg) external view override returns (uint256) {
        return legTurnover[user][weekId][leg];
    }

    function isRankQualified(address user) external view override returns (bool) {
        uint256 weekId = getCurrentWeekId();
        return _isRankQualified(user, weekId);
    }

    function getPendingBonus(address user) external view returns (uint256) {
        uint256 currentWeek = getCurrentWeekId();
        if (currentWeek <= 1) return 0;
        uint256 claimWeek = currentWeek - 1;
        if (weekBonusClaimed[user][claimWeek]) return 0;

        if (!_isRankQualified(user, claimWeek)) return 0;

        uint256 turnover = weeklyTurnoverData[user][claimWeek];
        uint256 rank = _getRankFromTurnover(turnover);
        if (rank == 0) return 0;

        uint256 bonusBP = _getRankBonusBP(rank);
        return (turnover * bonusBP) / OSLOConstants.BASIS_POINTS;
    }

    // ─── Internal Functions ─────────────────────────────────────────────

    /// @dev Check 40/60 leg ratio: main leg <= 40% of total, other legs >= 60% of total
    function _isRankQualified(address user, uint256 weekId) internal view returns (bool) {
        uint256 totalTurnover = weeklyTurnoverData[user][weekId];
        if (totalTurnover == 0) return false;

        if (referral == address(0)) return true; // No referral set — skip check during setup
        address[] memory directs = IReferral(referral).getDirectReferrals(user);
        if (directs.length == 0) return false;

        uint256 maxLegTurnover = 0;
        for (uint256 i = 0; i < directs.length; i++) {
            uint256 legT = legTurnover[user][weekId][directs[i]];
            if (legT > maxLegTurnover) maxLegTurnover = legT;
        }

        return maxLegTurnover * OSLOConstants.BASIS_POINTS <= totalTurnover * OSLOConstants.RANK_MAIN_LEG_MAX_BP;
    }

    /// @dev Progressive ranking — returns highest rank achieved (1-7, 0 for none)
    function _getRankFromTurnover(uint256 turnover) internal pure returns (uint256) {
        if (turnover >= OSLOConstants.RANK7_TURNOVER) return 7;
        if (turnover >= OSLOConstants.RANK6_TURNOVER) return 6;
        if (turnover >= OSLOConstants.RANK5_TURNOVER) return 5;
        if (turnover >= OSLOConstants.RANK4_TURNOVER) return 4;
        if (turnover >= OSLOConstants.RANK3_TURNOVER) return 3;
        if (turnover >= OSLOConstants.RANK2_TURNOVER) return 2;
        if (turnover >= OSLOConstants.RANK1_TURNOVER) return 1;
        return 0;
    }

    /// @dev Get bonus basis points for a rank (progressive, not cumulative)
    function _getRankBonusBP(uint256 rank) internal pure returns (uint256) {
        if (rank == 7) return OSLOConstants.RANK7_BONUS_BP;
        if (rank == 6) return OSLOConstants.RANK6_BONUS_BP;
        if (rank == 5) return OSLOConstants.RANK5_BONUS_BP;
        if (rank == 4) return OSLOConstants.RANK4_BONUS_BP;
        if (rank == 3) return OSLOConstants.RANK3_BONUS_BP;
        if (rank == 2) return OSLOConstants.RANK2_BONUS_BP;
        if (rank == 1) return OSLOConstants.RANK1_BONUS_BP;
        return 0;
    }
}

contracts/OSLOReferral.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./libraries/OSLOConstants.sol";
import "./interfaces/IReferral.sol";
import "./interfaces/IInvestmentEngine.sol";
import "./interfaces/IOSLODEX.sol";

/// @title OSLOReferral
/// @notice Decentralized 20-level referral tree with level unlocking and USDT commission distribution.
/// @dev V2: $1 USDT registration fee → routed to DEX as liquidity. OSLO received is burned.
contract OSLOReferral is IReferral, ReentrancyGuard {
    using SafeERC20 for IERC20;

    // ─── Structs ────────────────────────────────────────────────────────

    struct UserReferralInfo {
        address referrer;
        address[] directReferrals;
        uint256 unlockedLevels;
        uint256 totalEarned;        // Total USDT-equivalent commissions earned
        bool registered;
    }

    // ─── State ──────────────────────────────────────────────────────────

    IERC20 public immutable usdt;
    IERC20 public immutable osloToken;
    address public investmentEngine;
    address public osloDex;
    address public admin;
    address public timelock;
    bool public setupComplete;

    uint256 public constant REGISTRATION_FEE = 1 * 1e18; // $1 USDT

    mapping(address => UserReferralInfo) public userInfo;
    mapping(address => uint256) public referralRewards;    // USDT-denominated pending commissions
    mapping(address => mapping(uint256 => uint256)) public levelIncome; // Per-level income (USDT-denominated)
    uint256 public totalRegistered;
    uint256 public totalCommissionsPaid;
    uint256 public totalFeesCollected; // Total registration fees collected

    // ─── Events ─────────────────────────────────────────────────────────
    event UserRegistered(address indexed user, address indexed referrer);
    event LevelUnlocked(address indexed user, uint256 level);
    event ReferralPaid(address indexed upline, address indexed downline, uint256 level, uint256 amount);
    event ReferralRewardsClaimed(address indexed user, uint256 amount);
    event RegistrationFeeProcessed(address indexed user, uint256 fee, uint256 osloBurned);

    // ─── Errors ─────────────────────────────────────────────────────────
    error OnlyAdmin();
    error OnlyInvestmentEngine();
    error OnlyTimelock();
    error SetupAlreadyComplete();
    error AlreadyRegistered();
    error InvalidReferrer();
    error NotRegistered();
    error NothingToClaim();
    error SelfReferral();
    error ZeroAddress();

    modifier onlyAdmin() {
        if (msg.sender != admin) revert OnlyAdmin();
        _;
    }

    modifier onlyInvestmentEngine() {
        if (msg.sender != investmentEngine) revert OnlyInvestmentEngine();
        _;
    }

    modifier onlyTimelock() {
        if (msg.sender != timelock) revert OnlyTimelock();
        _;
    }

    constructor(address _usdt, address _osloToken) {
        if (_usdt == address(0) || _osloToken == address(0)) revert ZeroAddress();
        usdt = IERC20(_usdt);
        osloToken = IERC20(_osloToken);
        admin = msg.sender;
    }

    // ─── Setup ──────────────────────────────────────────────────────────

    function configure(
        address _investmentEngine,
        address _osloDex,
        address _timelock
    ) external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        investmentEngine = _investmentEngine;
        osloDex = _osloDex;
        timelock = _timelock;
    }

    function completeSetup() external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        setupComplete = true;
        admin = address(0);
    }

    // ─── Registration ($1 USDT Fee) ─────────────────────────────────────

    /// @notice Register a new user with a referrer. $1 USDT fee → DEX liquidity + OSLO burn.
    /// @dev $1 USDT is swapped for OSLO on DEX, then OSLO is permanently burned.
    function register(address user, address referrer) external override {
        if (user == address(0)) revert ZeroAddress();
        if (userInfo[user].registered) revert AlreadyRegistered();
        if (user == referrer) revert SelfReferral();
        if (referrer != address(0) && !userInfo[referrer].registered) revert InvalidReferrer();

        // Charge $1 USDT registration fee
        usdt.safeTransferFrom(user, address(this), REGISTRATION_FEE);
        totalFeesCollected += REGISTRATION_FEE;

        // Route fee to DEX as liquidity: swap USDT for OSLO, then burn OSLO
        if (osloDex != address(0)) {
            usdt.forceApprove(osloDex, REGISTRATION_FEE);
            try IOSLODEX(osloDex).swapUSDTForOSLO(REGISTRATION_FEE, 0) returns (uint256 osloReceived) {
                if (osloReceived > 0) {
                    osloToken.safeTransfer(OSLOConstants.DEAD_ADDRESS, osloReceived);
                    emit RegistrationFeeProcessed(user, REGISTRATION_FEE, osloReceived);
                }
            } catch {
                // If DEX swap fails (e.g. no reserves yet), USDT stays in contract
                // Can be recovered by admin before completeSetup
            }
        }

        userInfo[user].registered = true;
        userInfo[user].referrer = referrer;
        userInfo[user].unlockedLevels = 0;

        if (referrer != address(0)) {
            userInfo[referrer].directReferrals.push(user);
        }

        totalRegistered++;

        emit UserRegistered(user, referrer);
    }

    // ─── Level Unlocking ────────────────────────────────────────────────

    /// @notice Check and auto-unlock levels based on qualified direct referrals
    function checkAndUnlockLevels(address user) external override {
        if (!userInfo[user].registered) return;

        uint256 qualifiedDirects = _countQualifiedDirects(user);
        uint256 newLevel = _getMaxUnlockedLevel(qualifiedDirects);

        if (newLevel > userInfo[user].unlockedLevels) {
            uint256 oldLevel = userInfo[user].unlockedLevels;
            userInfo[user].unlockedLevels = newLevel;
            for (uint256 i = oldLevel + 1; i <= newLevel; i++) {
                emit LevelUnlocked(user, i);
            }
        }
    }

    // ─── Commission Distribution ────────────────────────────────────────

    /// @notice Distribute referral commissions on the profit portion of downline earnings.
    /// @dev Called by InvestmentEngine on each claim. Commissions accrue in USDT.
    /// @param user The user whose earnings generated the commission
    /// @param profitAmount The profit portion of the user's claim (USDT-denominated)
    function distributeReferralCommission(address user, uint256 profitAmount) external override {
        if (profitAmount == 0) return;

        address current = user;
        for (uint256 level = 1; level <= OSLOConstants.MAX_REFERRAL_LEVELS; level++) {
            address upline = userInfo[current].referrer;
            if (upline == address(0)) break;

            // Check if upline has this level unlocked
            if (userInfo[upline].unlockedLevels >= level) {
                uint256 commissionRate = _getCommissionRate(level);
                uint256 commission = (profitAmount * commissionRate) / OSLOConstants.BASIS_POINTS;

                if (commission > 0) {
                    referralRewards[upline] += commission;
                    levelIncome[upline][level] += commission;
                    userInfo[upline].totalEarned += commission;
                    totalCommissionsPaid += commission;

                    // Notify InvestmentEngine for combined 3X cap tracking
                    if (investmentEngine != address(0)) {
                        IInvestmentEngine(investmentEngine).notifyLevelIncome(upline, commission);
                    }

                    emit ReferralPaid(upline, user, level, commission);
                }
            }

            current = upline;
        }
    }

    /// @notice Claim accumulated referral rewards. Paid in USDT from contract balance.
    function claimReferralRewards() external override nonReentrant {
        uint256 amount = referralRewards[msg.sender];
        if (amount == 0) revert NothingToClaim();

        referralRewards[msg.sender] = 0;

        // Pay commission in USDT
        usdt.safeTransfer(msg.sender, amount);

        emit ReferralRewardsClaimed(msg.sender, amount);
    }

    /// @notice Update the InvestmentEngine address. Only callable by Timelock after setup.
    /// @dev Used when redeploying InvestmentEngine with new features.
    function setInvestmentEngine(address _investmentEngine) external onlyTimelock {
        investmentEngine = _investmentEngine;
    }

    // ─── View Functions ─────────────────────────────────────────────────

    function isRegistered(address user) external view override returns (bool) {
        return userInfo[user].registered;
    }

    function getReferrer(address user) external view override returns (address) {
        return userInfo[user].referrer;
    }

    function getDirectReferrals(address user) external view override returns (address[] memory) {
        return userInfo[user].directReferrals;
    }

    function getQualifiedDirectsCount(address user) external view override returns (uint256) {
        return _countQualifiedDirects(user);
    }

    function getUnlockedLevels(address user) external view override returns (uint256) {
        return userInfo[user].unlockedLevels;
    }

    function getTeamSize(address user) external view override returns (uint256) {
        return _getTeamSize(user, 0);
    }

    /// @notice Get level income earned at a specific level (USDT-denominated)
    function getLevelIncome(address user, uint256 level) external view returns (uint256) {
        return levelIncome[user][level];
    }

    /// @notice Get total and per-level income for all 20 levels (index 0 = total)
    /// @return Array of [total, L1, L2, ..., L20] (21 elements)
    function getAllLevelIncome(address user) external view returns (uint256[21] memory) {
        uint256[21] memory result;
        for (uint256 i = 1; i <= OSLOConstants.MAX_REFERRAL_LEVELS; i++) {
            result[i] = levelIncome[user][i];
            result[0] += result[i];
        }
        return result;
    }

    // ─── Internal Functions ─────────────────────────────────────────────

    /// @dev Count direct referrals with >= $100 active deposit
    function _countQualifiedDirects(address user) internal view returns (uint256) {
        uint256 count = 0;
        address[] storage directs = userInfo[user].directReferrals;
        for (uint256 i = 0; i < directs.length; i++) {
            if (investmentEngine != address(0)) {
                uint256 activeDeposit = IInvestmentEngine(investmentEngine).getActiveDeposit(directs[i]);
                if (activeDeposit >= OSLOConstants.QUALIFIED_DIRECT_MIN_DEPOSIT) {
                    count++;
                }
            }
        }
        return count;
    }

    /// @dev Get maximum unlocked level based on qualified directs count
    function _getMaxUnlockedLevel(uint256 qualifiedDirects) internal pure returns (uint256) {
        if (qualifiedDirects >= 7) return 20;
        if (qualifiedDirects >= 5) return 16;
        if (qualifiedDirects >= 3) return 12;
        if (qualifiedDirects >= 2) return 8;
        if (qualifiedDirects >= 1) return 3;
        return 0;
    }

    /// @dev Get commission rate for a specific level
    function _getCommissionRate(uint256 level) internal pure returns (uint256) {
        if (level == 1) return OSLOConstants.REFERRAL_L1_BP;
        if (level == 2) return OSLOConstants.REFERRAL_L2_BP;
        if (level >= 3 && level <= 10) return OSLOConstants.REFERRAL_L3_10_BP;
        if (level >= 11 && level <= 15) return OSLOConstants.REFERRAL_L11_15_BP;
        if (level >= 16 && level <= 20) return OSLOConstants.REFERRAL_L16_20_BP;
        return 0;
    }

    /// @dev Recursively count team size across 20 levels
    function _getTeamSize(address user, uint256 depth) internal view returns (uint256) {
        if (depth >= OSLOConstants.MAX_REFERRAL_LEVELS) return 0;

        address[] storage directs = userInfo[user].directReferrals;
        uint256 size = directs.length;
        for (uint256 i = 0; i < directs.length; i++) {
            size += _getTeamSize(directs[i], depth + 1);
        }
        return size;
    }
}

